import React from "react";
import Menu from "./Menu";
import TopBar from "./TopBar";
import Dashboard from "./Dashboard";

const Home = () => {
  return (
    <div className="nt-layout">
      {/* Left sidebar */}
      <Menu />

      {/* Right: topbar + content */}
      <div className="nt-main">
        <TopBar />
        <Dashboard />
      </div>
    </div>
  );
};

export default Home;
